"use client";

import { useState } from "react";
import { User, Lock, Mail } from "lucide-react";
import { AVATAR_GRADIENT } from "@/lib/constants/issue-config";
import { getInitials } from "@/lib/utils";
import { useAppStore } from "@/lib/stores/use-app-store";
import { useCurrentUser, useUpdateProfile, useChangePassword } from "@/features/auth/hooks";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Card, CardContent } from "@/components/ui/card";

export default function ProfilePage() {
  const { t } = useAppStore();
  const { user } = useCurrentUser();
  const { mutate: updateProfile, isPending: isUpdating } = useUpdateProfile();
  const { mutate: changePassword, isPending: isChanging } = useChangePassword();

  const [name, setName] = useState(user?.name ?? "");
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  // Sync name when user loads
  if (user?.name && !name) setName(user.name);

  function handleUpdateProfile(e: React.FormEvent) {
    e.preventDefault();
    if (!name.trim()) return;
    updateProfile({ name: name.trim() });
  }

  function handleChangePassword(e: React.FormEvent) {
    e.preventDefault();
    if (!currentPassword || !newPassword || newPassword !== confirmPassword) return;
    changePassword(
      { currentPassword, newPassword },
      {
        onSuccess: () => {
          setCurrentPassword("");
          setNewPassword("");
          setConfirmPassword("");
        },
      },
    );
  }

  const initials = getInitials(user?.name, user?.email);

  return (
    <div className="mx-auto max-w-2xl px-8 py-8">
      <h1 className="mb-1 text-2xl font-bold tracking-tight">{t("profile.title")}</h1>
      <p className="mb-8 text-sm text-muted-foreground">{t("profile.personalInfo")}</p>

      {/* Avatar + Info */}
      <Card className="mb-6">
        <CardContent className="flex items-center gap-5 p-6">
          <Avatar className="h-16 w-16">
            <AvatarFallback className={`${AVATAR_GRADIENT} text-xl`}>
              {initials}
            </AvatarFallback>
          </Avatar>
          <div>
            <h2 className="text-lg font-semibold">{user?.name || "User"}</h2>
            <p className="flex items-center gap-1.5 text-[13px] text-muted-foreground">
              <Mail className="h-3.5 w-3.5" />
              {user?.email}
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Update profile form */}
      <Card className="mb-6">
        <CardContent className="p-6">
          <h3 className="mb-4 flex items-center gap-2 text-[14px] font-semibold">
            <User className="h-4 w-4" />
            {t("profile.personalInfo")}
          </h3>
          <form onSubmit={handleUpdateProfile} className="space-y-4">
            <div>
              <label className="mb-1.5 block text-[13px] font-medium">{t("profile.nameLabel")}</label>
              <Input
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder={t("profile.nameLabel")}
              />
            </div>
            <div>
              <label className="mb-1.5 block text-[13px] font-medium">{t("profile.emailLabel")}</label>
              <Input
                value={user?.email ?? ""}
                disabled
                className="bg-muted"
              />
              <p className="mt-1 text-[11px] text-muted-foreground">
                Email cannot be changed.
              </p>
            </div>
            <Button type="submit" disabled={isUpdating || !name.trim()}>
              {isUpdating ? t("common.loading") : t("profile.updateProfile")}
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Change password */}
      <Card>
        <CardContent className="p-6">
          <h3 className="mb-4 flex items-center gap-2 text-[14px] font-semibold">
            <Lock className="h-4 w-4" />
            {t("profile.changePassword")}
          </h3>
          <form onSubmit={handleChangePassword} className="space-y-4">
            <div>
              <label className="mb-1.5 block text-[13px] font-medium">{t("profile.currentPassword")}</label>
              <Input
                type="password"
                value={currentPassword}
                onChange={(e) => setCurrentPassword(e.target.value)}
              />
            </div>
            <div>
              <label className="mb-1.5 block text-[13px] font-medium">{t("profile.newPassword")}</label>
              <Input
                type="password"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
              />
            </div>
            <div>
              <label className="mb-1.5 block text-[13px] font-medium">{t("profile.confirmNewPassword")}</label>
              <Input
                type="password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
              />
              {confirmPassword && newPassword !== confirmPassword && (
                <p className="mt-1 text-[11px] text-destructive">{t("validation.PASSWORD_MISMATCH")}</p>
              )}
            </div>
            <Button
              type="submit"
              disabled={isChanging || !currentPassword || !newPassword || newPassword !== confirmPassword}
            >
              {isChanging ? t("common.loading") : t("profile.changePassword")}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useParams, useRouter } from "next/navigation";
import {
  ChevronRight,
  Columns3,
  List,
  Plus,
  LayoutDashboard,
  Settings,
  Zap,
} from "lucide-react";
import Link from "next/link";
import { ROUTES } from "@/lib/constants";
import { useAppStore } from "@/lib/stores/use-app-store";
import {
  useProject,
  useBoard,
  useIssues,
  useMoveIssue,
  useCreateIssue,
  useCreateSprint,
  useUpdateSprint,
  useDeleteSprint,
  useStartSprint,
  useCompleteSprint,
  useUpdateIssue,
  useAddColumn,
  useUpdateColumn,
  useDeleteColumn,
} from "@/features/projects/hooks";
import { useWorkspace } from "@/features/workspaces/hooks";
import { BoardColumn } from "@/features/projects/components/board-column";
import { BacklogView } from "@/features/projects/components/backlog-view";
import { SummaryView } from "@/features/projects/components/summary-view";
import {
  BoardFilterBar,
  EMPTY_FILTERS,
  type BoardFilters,
} from "@/features/projects/components/board-filters";
import { CreateIssueDialog } from "@/features/projects/components/create-issue-dialog";
import { IssuePreviewModal } from "@/features/projects/components/issue-preview-modal";
import { EpicView } from "@/features/projects/components/epic-view";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import type {
  BoardColumn as BoardColumnType,
  UserPreview,
} from "@/features/projects/types";

export default function BoardPage() {
  const { workspaceId, projectId } = useParams<{
    workspaceId: string;
    projectId: string;
  }>();
  const router = useRouter();
  const { t } = useAppStore();
  const { data: workspace } = useWorkspace(workspaceId);
  const { data: project } = useProject(projectId);
  const { data: board, isLoading } = useBoard(projectId);
  const { data: allIssues } = useIssues(projectId);
  const { mutate: moveIssue } = useMoveIssue();
  const { mutate: createIssue } = useCreateIssue();
  const { mutate: createSprint, isPending: isCreatingSprint } =
    useCreateSprint(projectId);
  const { mutate: startSprint, isPending: isStartingSprint } =
    useStartSprint(projectId);
  const { mutate: completeSprint, isPending: isCompletingSprint } =
    useCompleteSprint(projectId);
  const { mutate: updateSprint } = useUpdateSprint(projectId);
  const { mutate: deleteSprint } = useDeleteSprint(projectId);
  const { mutate: updateIssue } = useUpdateIssue();
  const { mutate: addColumn } = useAddColumn(projectId);
  const { mutate: updateColumn } = useUpdateColumn(projectId);
  const { mutate: deleteColumn } = useDeleteColumn(projectId);

  const [filters, setFilters] = useState<BoardFilters>(EMPTY_FILTERS);
  const [showAddColumn, setShowAddColumn] = useState(false);
  const [newColumnName, setNewColumnName] = useState("");

  const activeSprint = board?.sprints.find((s) => s.status === "ACTIVE");

  const members: UserPreview[] = useMemo(() => {
    if (!project?.members) return [];
    return project.members.map((m) => m.user);
  }, [project]);

  const filteredColumns = useMemo(() => {
    if (!board?.columns) return [];
    return board.columns.map((col) => ({
      ...col,
      issues: col.issues.filter((issue) => {
        // Board tab: only show issues from active sprint
        if (
          activeSprint &&
          issue.sprintId &&
          issue.sprintId !== activeSprint.id
        )
          return false;
        if (
          filters.search &&
          !issue.summary.toLowerCase().includes(filters.search.toLowerCase()) &&
          !issue.key.toLowerCase().includes(filters.search.toLowerCase())
        )
          return false;
        if (filters.types.length > 0 && !filters.types.includes(issue.type))
          return false;
        if (
          filters.priorities.length > 0 &&
          !filters.priorities.includes(issue.priority)
        )
          return false;
        if (
          filters.assigneeIds.length > 0 &&
          (!issue.assigneeId || !filters.assigneeIds.includes(issue.assigneeId))
        )
          return false;
        return true;
      }),
    })) as BoardColumnType[];
  }, [board?.columns, filters, activeSprint]);

  function handleMoveIssue(issueId: string, columnId: string) {
    moveIssue({ id: issueId, columnId, position: 0 });
  }

  const [previewKey, setPreviewKey] = useState<string | null>(null);

  function handleClickIssue(key: string) {
    setPreviewKey(key);
  }

  function handleQuickCreate(summary: string) {
    createIssue({ projectId, summary });
  }

  function handleAddColumn(e: React.FormEvent) {
    e.preventDefault();
    if (!newColumnName.trim() || !board) return;
    addColumn({ boardId: board.id, name: newColumnName.trim() });
    setNewColumnName("");
    setShowAddColumn(false);
  }

  const addColumnUI = showAddColumn ? (
    <form
      onSubmit={handleAddColumn}
      className="flex h-fit w-68 shrink-0 flex-col gap-2 rounded-lg bg-muted/40 p-3"
    >
      <Input
        placeholder={t("board.columnName")}
        value={newColumnName}
        onChange={(e) => setNewColumnName(e.target.value)}
        className="h-8 text-[12px]"
        autoFocus
      />
      <div className="flex gap-2">
        <Button size="xs" type="submit" disabled={!newColumnName.trim()}>
          {t("common.add")}
        </Button>
        <Button
          size="xs"
          variant="ghost"
          type="button"
          onClick={() => setShowAddColumn(false)}
        >
          {t("common.cancel")}
        </Button>
      </div>
    </form>
  ) : (
    <button
      onClick={() => setShowAddColumn(true)}
      className="flex h-10 w-68 shrink-0 items-center justify-center gap-1.5 rounded-lg border border-dashed text-[12px] text-muted-foreground transition-colors hover:border-primary/30 hover:bg-muted/40 hover:text-foreground"
    >
      <Plus className="h-3.5 w-3.5" />
      {t("board.addColumn")}
    </button>
  );

  const columnsView = (
    <>
      {filteredColumns.map((column) => (
        <BoardColumn
          key={column.id}
          column={column}
          onMoveIssue={handleMoveIssue}
          onClickIssue={handleClickIssue}
          onQuickCreate={handleQuickCreate}
          onDeleteColumn={(colId) =>
            board && deleteColumn({ boardId: board.id, columnId: colId })
          }
          onUpdateWipLimit={(colId, wipLimit) =>
            board &&
            updateColumn({ boardId: board.id, columnId: colId, wipLimit })
          }
        />
      ))}
      {addColumnUI}
    </>
  );

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <div className="flex items-center justify-between border-b px-6 py-3">
        <div>
          <div className="mb-0.5 flex items-center gap-1 text-[12px] text-muted-foreground">
            <Link
              href={ROUTES.WORKSPACES}
              className="hover:text-foreground hover:underline"
            >
              {t("nav.workspaces")}
            </Link>
            <ChevronRight className="h-3 w-3" />
            <Link
              href={ROUTES.WORKSPACE(workspaceId)}
              className="hover:text-foreground hover:underline"
            >
              {workspace?.name ?? "..."}
            </Link>
            <ChevronRight className="h-3 w-3" />
            <span className="font-medium text-foreground">
              {project?.key ?? "..."}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <h1 className="text-base font-semibold">
              {project?.name ?? "Board"}
            </h1>
            {activeSprint && (
              <Badge
                variant="secondary"
                className="gap-1 text-[10px] bg-blue-50 text-blue-700"
              >
                <span className="h-1.5 w-1.5 rounded-full bg-blue-500 animate-pulse" />
                {activeSprint.name}
              </Badge>
            )}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <CreateIssueDialog
            projectId={projectId}
            sprints={board?.sprints ?? []}
          />
          <Link href={ROUTES.PROJECT_SETTINGS(workspaceId, projectId)}>
            <Button
              variant="ghost"
              size="icon-xs"
              className="text-muted-foreground"
            >
              <Settings className="h-4 w-4" />
            </Button>
          </Link>
        </div>
      </div>

      {/* Content */}
      {isLoading ? (
        <div className="flex gap-3 overflow-auto p-5">
          {Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="h-96 w-68 shrink-0 rounded-lg" />
          ))}
        </div>
      ) : board?.type === "SCRUM" ? (
        <Tabs
          defaultValue="summary"
          className="flex flex-1 flex-col overflow-hidden"
        >
          <div className="border-b px-6">
            <TabsList variant="line">
              <TabsTrigger value="summary">
                <LayoutDashboard className="mr-1.5 h-3.5 w-3.5" />
                {t("board.summary")}
              </TabsTrigger>
              <TabsTrigger value="epics">
                <Zap className="mr-1.5 h-3.5 w-3.5" />
                {t("issue.epics")}
              </TabsTrigger>
              <TabsTrigger value="backlog">
                <List className="mr-1.5 h-3.5 w-3.5" />
                {t("board.backlog")}
                {board.sprints.length > 0 && (
                  <Badge
                    variant="secondary"
                    className="ml-1.5 px-1.5 text-[10px]"
                  >
                    {board.sprints.length}
                  </Badge>
                )}
              </TabsTrigger>
              <TabsTrigger value="board">
                <Columns3 className="mr-1.5 h-3.5 w-3.5" />
                {t("board.board")}
                {activeSprint && (
                  <Badge
                    variant="secondary"
                    className="ml-1.5 px-1.5 text-[10px] bg-blue-50 text-blue-700"
                  >
                    {activeSprint.name}
                  </Badge>
                )}
              </TabsTrigger>
            </TabsList>
          </div>
          <TabsContent value="summary" className="flex-1 overflow-auto">
            <SummaryView
              board={board}
              allIssues={allIssues ?? []}
              members={project?.members ?? []}
            />
          </TabsContent>
          <TabsContent value="epics" className="flex-1 overflow-auto">
            <EpicView projectId={projectId} onClickIssue={handleClickIssue} />
          </TabsContent>
          <TabsContent value="backlog" className="flex-1 overflow-auto">
            <BacklogView
              board={board}
              allIssues={allIssues ?? []}
              projectId={projectId}
              onCreateSprint={(boardId, name) =>
                createSprint({ boardId, name })
              }
              onStartSprint={startSprint}
              onCompleteSprint={completeSprint}
              onUpdateSprint={(id, data) => updateSprint({ id, ...data })}
              onDeleteSprint={deleteSprint}
              onUpdateIssue={(id, data) => updateIssue({ id, ...data })}
              onClickIssue={handleClickIssue}
              members={members}
              isCreatingSprint={isCreatingSprint}
              isStartingSprint={isStartingSprint}
              isCompletingSprint={isCompletingSprint}
            />
          </TabsContent>
          <TabsContent
            value="board"
            className="flex flex-1 flex-col overflow-hidden"
          >
            {activeSprint ? (
              <>
                <div className="border-b px-5 py-2.5">
                  <BoardFilterBar
                    filters={filters}
                    onChange={setFilters}
                    members={members}
                  />
                </div>
                <div className="flex flex-1 gap-3 overflow-auto p-5">
                  {columnsView}
                </div>
              </>
            ) : (
              <div className="flex flex-1 flex-col items-center justify-center gap-2 text-muted-foreground">
                <Columns3 className="h-10 w-10 opacity-30" />
                <p className="text-[13px] font-medium">
                  {t("board.noActiveSprint")}
                </p>
                <p className="text-[12px]">{t("board.noActiveSprintDesc")}</p>
              </div>
            )}
          </TabsContent>
        </Tabs>
      ) : (
        <div className="flex flex-1 flex-col overflow-hidden">
          <div className="border-b px-5 py-2.5">
            <BoardFilterBar
              filters={filters}
              onChange={setFilters}
              members={members}
            />
          </div>
          <div className="flex flex-1 gap-3 overflow-auto p-5">
            {columnsView}
          </div>
        </div>
      )}
      {/* Issue preview modal */}
      {previewKey && (
        <IssuePreviewModal
          issueKey={previewKey}
          onClose={() => setPreviewKey(null)}
        />
      )}
    </div>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  LayoutDashboard,
  FolderKanban,
  Plus,
  PanelLeftClose,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { ROUTES } from "@/lib/constants";
import { useAppStore } from "@/lib/stores/use-app-store";
import { useWorkspaces } from "@/features/workspaces/hooks";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";

export function Sidebar({
  collapsed,
  onToggle,
}: {
  collapsed: boolean;
  onToggle: () => void;
}) {
  const pathname = usePathname();
  const { name: appName, logoUrl, authorName, authorUrl, t } = useAppStore();
  const { data: workspaces } = useWorkspaces();

  const navItems = [
    { href: ROUTES.DASHBOARD, label: t("nav.dashboard"), icon: LayoutDashboard },
    { href: ROUTES.WORKSPACES, label: t("nav.workspaces"), icon: FolderKanban },
  ];

  if (collapsed) return null;

  return (
    <aside className="flex h-screen w-60 shrink-0 flex-col border-r bg-muted/30">
      {/* Brand + collapse */}
      <div className="flex h-12 items-center justify-between px-4">
        <Link href={ROUTES.DASHBOARD} className="flex items-center gap-2">
          {logoUrl ? (
            <img src={logoUrl} alt={appName} className="h-6 w-6 rounded" />
          ) : (
            <div className="flex h-6 w-6 items-center justify-center rounded-md bg-primary text-[10px] font-bold text-primary-foreground">
              J
            </div>
          )}
          <span className="text-[13px] font-semibold">
            {appName}
          </span>
        </Link>
        <button
          onClick={onToggle}
          className="rounded-md p-1 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
        >
          <PanelLeftClose className="h-4 w-4" />
        </button>
      </div>

      <ScrollArea className="flex-1">
        {/* Main nav */}
        <div className="px-3 py-1">
          <nav className="space-y-0.5">
            {navItems.map((item) => (
              <Link
                key={item.href}
                href={item.href}
                className={cn(
                  "flex items-center gap-2.5 rounded-md px-2.5 py-1.75 text-[13px] font-medium transition-colors",
                  pathname === item.href
                    ? "bg-primary/8 text-primary"
                    : "text-muted-foreground hover:bg-muted hover:text-foreground",
                )}
              >
                <item.icon className="h-4.5 w-4.5 shrink-0" />
                {item.label}
              </Link>
            ))}
          </nav>
        </div>

        <div className="px-3 py-1">
          <Separator />
        </div>

        {/* Workspaces */}
        <div className="px-3 py-1">
          <div className="mb-1 flex items-center justify-between px-2.5">
            <span className="text-[11px] font-medium text-muted-foreground">
              {t("nav.workspaces")}
            </span>
            <Link
              href={ROUTES.WORKSPACES}
              className="rounded p-0.5 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
              title={t("nav.newWorkspace")}
            >
              <Plus className="h-3.5 w-3.5" />
            </Link>
          </div>

          <div className="space-y-0.5">
            {Array.isArray(workspaces) &&
              workspaces.map((ws) => {
                const isActive = pathname.includes(ws.id);
                return (
                  <Link
                    key={ws.id}
                    href={ROUTES.WORKSPACE(ws.id)}
                    className={cn(
                      "flex items-center gap-2.5 rounded-md px-2.5 py-1.5 text-[13px] transition-colors",
                      isActive
                        ? "bg-primary/8 text-primary font-medium"
                        : "text-muted-foreground hover:bg-muted hover:text-foreground",
                    )}
                  >
                    <span
                      className={cn(
                        "flex h-5 w-5 shrink-0 items-center justify-center rounded text-[10px] font-semibold",
                        isActive
                          ? "bg-primary text-primary-foreground"
                          : "bg-muted-foreground/15 text-muted-foreground",
                      )}
                    >
                      {ws.name.charAt(0).toUpperCase()}
                    </span>
                    <span className="truncate">{ws.name}</span>
                    <span className="ml-auto text-[10px] text-muted-foreground/60">
                      {ws._count?.projects ?? 0}
                    </span>
                  </Link>
                );
              })}
          </div>
        </div>
      </ScrollArea>

      {/* App info footer */}
      <div className="border-t px-4 py-3 text-center">
        <p className="text-[10px] text-muted-foreground/50">
          {t("footer.copyright", { year: new Date().getFullYear().toString(), name: appName })}
          {authorName && (
            <>
              {" · "}
              {t("footer.builtBy")}{" "}
              {authorUrl ? (
                <a
                  href={authorUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="underline underline-offset-2 hover:text-muted-foreground"
                >
                  {authorName}
                </a>
              ) : (
                authorName
              )}
            </>
          )}
        </p>
      </div>
    </aside>
  );
}

