"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import type { z } from "zod";
import { useAppStore } from "@/lib/stores/use-app-store";
import { ROUTES } from "@/lib/constants";
import { forgotPasswordSchema } from "@/features/auth/schemas";
import { useForgotPassword } from "@/features/auth/hooks";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Form, FormField, FormItem, FormLabel, FormControl, FormMessage } from "@/components/ui/form";

type ForgotPasswordForm = z.infer<typeof forgotPasswordSchema>;

export function ForgotPasswordForm() {
  const { t } = useAppStore();

  const form = useForm<ForgotPasswordForm>({
    resolver: zodResolver(forgotPasswordSchema),
    defaultValues: { email: "" },
  });

  const email = form.watch("email");

  const { mutate: forgotPassword, isPending } = useForgotPassword({
    onSuccess: () => {
      window.location.href = `${ROUTES.RESET_PASSWORD}?email=${encodeURIComponent(email)}`;
    },
  });

  const te = (key: string) => t(`validation.${key}` as "validation.EMAIL_INVALID");

  return (
    <div>
      <div className="mb-6 text-center">
        <h1 className="text-xl font-semibold">{t("auth.forgotPasswordTitle")}</h1>
        <p className="mt-1 text-sm text-muted-foreground">{t("auth.forgotPasswordDesc")}</p>
      </div>

      <Form {...form}>
        <div className="space-y-4">
          <FormField
            control={form.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormLabel>{t("auth.email")}</FormLabel>
                <FormControl>
                  <Input type="email" placeholder="you@example.com" {...field} />
                </FormControl>
                <FormMessage renderMessage={te} />
              </FormItem>
            )}
          />

          <Button type="button" className="w-full p-5" disabled={isPending} onClick={form.handleSubmit((data) => forgotPassword(data))}>
            {isPending ? t("auth.sending") : t("auth.sendResetCode")}
          </Button>
        </div>
      </Form>

      <p className="mt-6 text-center text-sm text-muted-foreground">
        <a href={ROUTES.SIGN_IN} className="text-primary hover:underline">{t("auth.backToSignIn")}</a>
      </p>
    </div>
  );
}

"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import type { z } from "zod";
import { useAppStore } from "@/lib/stores/use-app-store";
import { ROUTES } from "@/lib/constants";
import { registerFormSchema } from "@/features/auth/schemas";
import { useRegister } from "@/features/auth/hooks";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Form, FormField, FormItem, FormLabel, FormControl, FormMessage } from "@/components/ui/form";

type RegisterForm = z.infer<typeof registerFormSchema>;

export function SignUpForm() {
  const { t } = useAppStore();

  const { mutate: registerUser, isPending } = useRegister();

  const form = useForm<RegisterForm>({
    resolver: zodResolver(registerFormSchema),
    defaultValues: { name: "", email: "", password: "", confirmPassword: "" },
  });

  function onSubmit(data: RegisterForm) {
    const { confirmPassword: _, ...payload } = data;
    registerUser(payload);
  }

  const te = (key: string) => t(`validation.${key}` as "validation.EMAIL_INVALID");

  return (
    <div>
      <div className="mb-6 text-center">
        <h1 className="text-xl font-semibold">{t("auth.signUp")}</h1>
        <p className="mt-1 text-sm text-muted-foreground">{t("auth.signUpDesc")}</p>
      </div>

      <Form {...form}>
        <div className="space-y-4">
          <FormField
            control={form.control}
            name="name"
            render={({ field }) => (
              <FormItem>
                <FormLabel>{t("auth.name")}</FormLabel>
                <FormControl>
                  <Input type="text" {...field} />
                </FormControl>
                <FormMessage renderMessage={te} />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormLabel>{t("auth.email")}</FormLabel>
                <FormControl>
                  <Input type="email" placeholder="you@example.com" {...field} />
                </FormControl>
                <FormMessage renderMessage={te} />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="password"
            render={({ field }) => (
              <FormItem>
                <FormLabel>{t("auth.password")}</FormLabel>
                <FormControl>
                  <Input type="password" placeholder={t("auth.passwordHint")} {...field} />
                </FormControl>
                <FormMessage renderMessage={te} />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="confirmPassword"
            render={({ field }) => (
              <FormItem>
                <FormLabel>{t("auth.confirmPassword")}</FormLabel>
                <FormControl>
                  <Input type="password" {...field} />
                </FormControl>
                <FormMessage renderMessage={te} />
              </FormItem>
            )}
          />

          <Button type="button" className="w-full p-5" disabled={isPending} onClick={form.handleSubmit(onSubmit)}>
            {isPending ? t("auth.processing") : t("auth.signUp")}
          </Button>
        </div>
      </Form>

      <p className="mt-6 text-center text-sm text-muted-foreground">
        {t("auth.hasAccount")}{" "}
        <a href={ROUTES.SIGN_IN} className="text-primary hover:underline">{t("auth.signIn")}</a>
      </p>
    </div>
  );
}

"use client";

import { useCallback, useState } from "react";
import {
  Paperclip,
  Trash2,
  Download,
  FileText,
  X,
  ChevronDown,
  ChevronRight,
  MoreHorizontal,
} from "lucide-react";
import { getInitials, formatDateShort } from "@/lib/utils";
import { useAppStore } from "@/lib/stores/use-app-store";
import { useAttachments, useUploadAttachments, useDeleteAttachment } from "../hooks";
import { Spinner } from "@/components/ui/spinner";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import type { Attachment } from "../types";

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

function isImage(mimeType: string): boolean {
  return mimeType.startsWith("image/");
}

export function AttachmentSection({
  issueId,
  currentUserId,
}: {
  issueId: string;
  currentUserId: string;
}) {
  const { t } = useAppStore();
  const { data: attachments } = useAttachments(issueId);
  const { mutate: upload, isPending: uploading } = useUploadAttachments(issueId);
  const { mutate: deleteAttachment } = useDeleteAttachment(issueId);
  const [expanded, setExpanded] = useState(true);
  const [dragOver, setDragOver] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);

  const count = attachments?.length ?? 0;

  const handleFiles = useCallback(
    (fileList: FileList | File[]) => {
      const files = Array.from(fileList).filter((f) => f.size <= 10 * 1024 * 1024);
      if (files.length > 0) upload(files);
    },
    [upload],
  );

  function handleDrop(e: React.DragEvent) {
    e.preventDefault();
    setDragOver(false);
    if (e.dataTransfer.files.length > 0) handleFiles(e.dataTransfer.files);
  }

  return (
    <div className="mb-8">
      {/* Header — collapsible */}
      <div className="mb-3 flex items-center gap-2">
        <button
          onClick={() => setExpanded(!expanded)}
          className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground"
        >
          {expanded ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
        </button>
        <h3 className="flex items-center gap-1.5 text-[13px] font-semibold uppercase tracking-wide text-muted-foreground">
          <Paperclip className="h-3.5 w-3.5" />
          {t("issue.attachments")}
          {count > 0 && <span className="ml-1 normal-case font-normal">({count})</span>}
        </h3>

        {/* Menu */}
        <DropdownMenu>
          <Button render={<DropdownMenuTrigger />} variant="ghost" size="icon-xs" className="ml-auto h-5 w-5 text-muted-foreground">
            <MoreHorizontal className="h-3.5 w-3.5" />
          </Button>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={() => document.getElementById(`file-upload-${issueId}`)?.click()}>
              <Paperclip className="mr-2 h-3.5 w-3.5" />
              {t("issue.dropOrClick")}
            </DropdownMenuItem>
            <input
              id={`file-upload-${issueId}`}
              type="file"
              multiple
              className="hidden"
              onChange={(e) => e.target.files && handleFiles(e.target.files)}
            />
          </DropdownMenuContent>
        </DropdownMenu>
      </div>

      {expanded && (
        <>
          {/* Drop zone wrapping everything */}
          <div
            onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
            onDragLeave={() => setDragOver(false)}
            onDrop={handleDrop}
            className={`rounded-lg border-2 border-dashed p-3 transition-colors duration-150 ${
              dragOver
                ? "border-primary bg-primary/5 dark:bg-primary/10"
                : "border-muted-foreground/20 hover:border-muted-foreground/30"
            }`}
          >
            {/* Upload hint */}
            <label className="mb-3 flex cursor-pointer items-center justify-center gap-2 rounded-md py-2 text-[12px] text-muted-foreground transition-colors hover:bg-muted/40">
              {uploading ? (
                <Spinner className="h-4 w-4" />
              ) : (
                <Paperclip className="h-4 w-4" />
              )}
              <span>{uploading ? t("common.loading") : t("issue.dropOrClick")}</span>
              <input
                type="file"
                multiple
                className="hidden"
                onChange={(e) => e.target.files && handleFiles(e.target.files)}
              />
            </label>

            {/* Attachment grid inside drop zone */}
            {count > 0 && (
            <div className="grid grid-cols-2 gap-2 sm:grid-cols-3">
              {attachments!.map((att) => (
                <div
                  key={att.id}
                  className="group relative overflow-hidden rounded-lg border bg-card transition-all duration-150 hover:shadow-md"
                >
                  {/* Thumbnail / file icon */}
                  {isImage(att.mimeType) ? (
                    <button
                      onClick={() => setPreview(att.fileUrl)}
                      className="block h-28 w-full overflow-hidden bg-muted"
                    >
                      <img
                        src={att.fileUrl}
                        alt={att.fileName}
                        className="h-full w-full object-cover transition-transform duration-200 group-hover:scale-105"
                      />
                    </button>
                  ) : (
                    <a
                      href={att.fileUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex h-28 w-full items-center justify-center bg-muted/50"
                    >
                      <FileText className="h-10 w-10 text-muted-foreground/30" />
                    </a>
                  )}

                  {/* Info bar */}
                  <div className="px-2 py-1.5">
                    <a
                      href={att.fileUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block truncate text-[11px] font-medium hover:text-primary hover:underline"
                    >
                      {att.fileName}
                    </a>
                    <span className="text-[10px] text-muted-foreground">
                      {formatSize(att.fileSize)} · {formatDateShort(att.createdAt)}
                    </span>
                  </div>

                  {/* Hover actions */}
                  <div className="absolute top-1.5 right-1.5 flex gap-1 opacity-0 transition-opacity group-hover:opacity-100">
                    <a
                      href={att.fileUrl}
                      download={att.fileName}
                      className="rounded-md bg-black/50 p-1 text-white hover:bg-black/70"
                    >
                      <Download className="h-3 w-3" />
                    </a>
                    {att.uploadedById === currentUserId && (
                      <button
                        onClick={() => deleteAttachment(att.id)}
                        className="rounded-md bg-black/50 p-1 text-white hover:bg-red-600"
                      >
                        <Trash2 className="h-3 w-3" />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
          </div>
        </>
      )}

      {/* Image preview modal */}
      {preview && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70" onClick={() => setPreview(null)}>
          <button onClick={() => setPreview(null)} className="absolute top-4 right-4 rounded-full bg-black/50 p-2 text-white hover:bg-black/70">
            <X className="h-5 w-5" />
          </button>
          <img src={preview} alt="Preview" className="max-h-[85vh] max-w-[90vw] rounded-lg shadow-2xl" />
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { X, Trash2, UserPlus, Zap, ArrowUp } from "lucide-react";
import { PRIORITIES } from "@/lib/constants/issue-config";
import { useAppStore } from "@/lib/stores/use-app-store";
import { useBulkUpdateIssues, useBulkDeleteIssues } from "../hooks";
import { Button } from "@/components/ui/button";
import { Spinner } from "@/components/ui/spinner";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import type { Sprint, UserPreview } from "../types";

export function BulkActionBar({
  selectedIds,
  projectId,
  sprints,
  members,
  onClear,
}: {
  selectedIds: Set<string>;
  projectId: string;
  sprints: Sprint[];
  members: UserPreview[];
  onClear: () => void;
}) {
  const { t } = useAppStore();
  const { mutate: bulkUpdate, isPending: updating } = useBulkUpdateIssues(projectId);
  const { mutate: bulkDelete, isPending: deleting } = useBulkDeleteIssues(projectId);
  const count = selectedIds.size;

  if (count === 0) return null;

  const ids = Array.from(selectedIds);

  function handleMoveSprint(sprintId: string | null) {
    bulkUpdate({ issueIds: ids, sprintId }, { onSuccess: onClear });
  }

  function handleAssign(assigneeId: string | null) {
    bulkUpdate({ issueIds: ids, assigneeId }, { onSuccess: onClear });
  }

  function handlePriority(priority: string) {
    bulkUpdate({ issueIds: ids, priority }, { onSuccess: onClear });
  }

  function handleDelete() {
    if (!window.confirm(`Delete ${count} issue(s)? This cannot be undone.`)) return;
    bulkDelete(ids, { onSuccess: onClear });
  }

  return (
    <div className="fixed bottom-6 left-1/2 z-40 flex -translate-x-1/2 items-center gap-3 rounded-xl border bg-popover px-4 py-2.5 shadow-2xl dark:shadow-none">
      {/* Count + clear */}
      <div className="flex items-center gap-2">
        <span className="flex h-6 min-w-6 items-center justify-center rounded-md bg-primary px-1.5 text-[11px] font-bold text-primary-foreground">
          {count}
        </span>
        <span className="text-[12px] font-medium">{t("common.selected") || "selected"}</span>
        <button onClick={onClear} className="rounded p-0.5 text-muted-foreground hover:text-foreground">
          <X className="h-3.5 w-3.5" />
        </button>
      </div>

      <div className="h-5 w-px bg-border" />

      {/* Move to sprint */}
      <Select onValueChange={(v) => handleMoveSprint(v === "__backlog__" ? null : v as string)}>
        <SelectTrigger className="h-7 w-auto gap-1.5 text-[11px]">
          <Zap className="h-3 w-3" />
          Sprint
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="__backlog__">Backlog</SelectItem>
          {sprints.map((s) => (
            <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Assign */}
      <Select onValueChange={(v) => handleAssign(v === "__none__" ? null : v as string)}>
        <SelectTrigger className="h-7 w-auto gap-1.5 text-[11px]">
          <UserPlus className="h-3 w-3" />
          {t("issue.assignee")}
        </SelectTrigger>
        <SelectContent>
          <SelectItem value="__none__">{t("issue.unassigned")}</SelectItem>
          {members.map((m) => (
            <SelectItem key={m.id} value={m.id}>{m.name || m.email}</SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Priority */}
      <Select onValueChange={(v) => handlePriority(v as string)}>
        <SelectTrigger className="h-7 w-auto gap-1.5 text-[11px]">
          <ArrowUp className="h-3 w-3" />
          {t("issue.priority")}
        </SelectTrigger>
        <SelectContent>
          {PRIORITIES.map((p) => (
            <SelectItem key={p} value={p}>{t(`issue.priorities.${p}` as any)}</SelectItem>
          ))}
        </SelectContent>
      </Select>

      <div className="h-5 w-px bg-border" />

      {/* Delete */}
      <Button size="xs" variant="destructive" onClick={handleDelete} disabled={deleting}>
        {deleting ? <Spinner className="mr-1 h-3 w-3" /> : <Trash2 className="mr-1 h-3 w-3" />}
        {t("common.delete")}
      </Button>

      {updating && <Spinner className="h-4 w-4 text-primary" />}
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useRouter } from "next/navigation";
import { Zap, Plus, ChevronDown, ChevronRight, CheckCircle2, Circle, Clock } from "lucide-react";
import { ROUTES } from "@/lib/constants";
import { STATUS_BADGE_COLORS } from "@/lib/constants/issue-config";
import { useAppStore } from "@/lib/stores/use-app-store";
import { useIssues, useCreateIssue } from "../hooks";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import type { Issue } from "../types";

type EpicFilter = "all" | "open" | "done";

export function EpicView({
  projectId,
  onClickIssue,
}: {
  projectId: string;
  onClickIssue: (key: string) => void;
}) {
  const { t } = useAppStore();
  const { data: allIssues } = useIssues(projectId);
  const { mutate: createIssue, isPending } = useCreateIssue();
  const [filter, setFilter] = useState<EpicFilter>("all");
  const [showCreate, setShowCreate] = useState(false);
  const [newEpicName, setNewEpicName] = useState("");

  const { epics, childrenByEpic } = useMemo(() => {
    if (!allIssues) return { epics: [], childrenByEpic: new Map<string, Issue[]>() };

    const epicList = allIssues.filter((i) => i.type === "EPIC");
    const map = new Map<string, Issue[]>();

    for (const issue of allIssues) {
      if (issue.epicId) {
        const existing = map.get(issue.epicId) ?? [];
        existing.push(issue);
        map.set(issue.epicId, existing);
      }
    }

    return { epics: epicList, childrenByEpic: map };
  }, [allIssues]);

  const filteredEpics = useMemo(() => {
    return epics.filter((epic) => {
      if (filter === "all") return true;
      const children = childrenByEpic.get(epic.id) ?? [];
      const doneCount = children.filter((c) => c.boardColumn?.category === "DONE").length;
      const allDone = children.length > 0 && doneCount === children.length;
      if (filter === "done") return allDone;
      return !allDone; // "open"
    });
  }, [epics, childrenByEpic, filter]);

  function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    if (!newEpicName.trim()) return;
    createIssue(
      { projectId, summary: newEpicName.trim(), type: "EPIC" },
      { onSuccess: () => { setNewEpicName(""); setShowCreate(false); } },
    );
  }

  return (
    <div className="p-5">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          {(["all", "open", "done"] as const).map((f) => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`rounded-md px-3 py-1 text-[12px] font-medium transition-colors ${
                filter === f
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:bg-muted"
              }`}
            >
              {f === "all" ? "All" : f === "open" ? "Open" : "Done"}
              {f === "all" && ` (${epics.length})`}
            </button>
          ))}
        </div>
        <Button size="sm" onClick={() => setShowCreate(true)}>
          <Plus className="mr-1.5 h-3.5 w-3.5" />
          {t("issue.createEpic")}
        </Button>
      </div>

      {/* Create form */}
      {showCreate && (
        <form onSubmit={handleCreate} className="mb-4 flex gap-2">
          <Input
            value={newEpicName}
            onChange={(e) => setNewEpicName(e.target.value)}
            placeholder="Epic name..."
            className="h-9 text-[13px]"
            autoFocus
          />
          <Button size="sm" type="submit" disabled={isPending || !newEpicName.trim()}>
            {t("common.create")}
          </Button>
          <Button size="sm" variant="ghost" type="button" onClick={() => setShowCreate(false)}>
            {t("common.cancel")}
          </Button>
        </form>
      )}

      {/* Epic list */}
      {filteredEpics.length === 0 ? (
        <div className="rounded-lg border border-dashed py-12 text-center text-[13px] text-muted-foreground">
          <Zap className="mx-auto mb-2 h-8 w-8 opacity-20" />
          No epics found
        </div>
      ) : (
        <div className="space-y-2">
          {filteredEpics.map((epic) => (
            <EpicCard
              key={epic.id}
              epic={epic}
              children={childrenByEpic.get(epic.id) ?? []}
              onClickIssue={onClickIssue}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function EpicCard({
  epic,
  children,
  onClickIssue,
}: {
  epic: Issue;
  children: Issue[];
  onClickIssue: (key: string) => void;
}) {
  const [expanded, setExpanded] = useState(false);

  const doneCount = children.filter((c) => c.boardColumn?.category === "DONE").length;
  const total = children.length;
  const percent = total > 0 ? Math.round((doneCount / total) * 100) : 0;

  return (
    <div className="rounded-lg border bg-card">
      {/* Header */}
      <div className="flex items-center gap-2.5 px-4 py-3">
        <button
          onClick={() => setExpanded(!expanded)}
          className="text-muted-foreground hover:text-foreground"
        >
          {expanded ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
        </button>

        <div className="flex h-5 w-5 items-center justify-center rounded-sm bg-purple-600">
          <Zap className="h-3 w-3 text-white" />
        </div>

        <button
          onClick={() => onClickIssue(epic.key)}
          className="text-[13px] font-semibold hover:text-primary hover:underline"
        >
          {epic.summary}
        </button>

        <span className="text-[11px] text-muted-foreground">{epic.key}</span>

        {/* Progress */}
        {total > 0 && (
          <div className="ml-auto flex items-center gap-2">
            <div className="h-1.5 w-24 overflow-hidden rounded-full bg-muted">
              <div
                className="h-full rounded-full bg-green-500 transition-all"
                style={{ width: `${percent}%` }}
              />
            </div>
            <span className="text-[10px] text-muted-foreground">
              {doneCount}/{total}
            </span>
          </div>
        )}

        {total === 0 && (
          <span className="ml-auto text-[10px] text-muted-foreground">No issues</span>
        )}
      </div>

      {/* Children */}
      {expanded && total > 0 && (
        <div className="border-t">
          {children.map((child) => {
            const isDone = child.boardColumn?.category === "DONE";
            return (
              <button
                key={child.id}
                onClick={() => onClickIssue(child.key)}
                className="flex w-full items-center gap-2.5 border-b px-4 py-2 text-left text-[12px] last:border-b-0 transition-colors hover:bg-muted/50"
              >
                {isDone ? (
                  <CheckCircle2 className="h-3.5 w-3.5 shrink-0 text-green-500" />
                ) : child.boardColumn?.category === "IN_PROGRESS" ? (
                  <Clock className="h-3.5 w-3.5 shrink-0 text-blue-500" />
                ) : (
                  <Circle className="h-3.5 w-3.5 shrink-0 text-muted-foreground/40" />
                )}
                <span className="shrink-0 font-medium text-muted-foreground">{child.key}</span>
                <span className={`min-w-0 flex-1 truncate ${isDone ? "line-through text-muted-foreground/60" : ""}`}>
                  {child.summary}
                </span>
                {child.boardColumn && (
                  <Badge variant="secondary" className={`shrink-0 text-[10px] ${STATUS_BADGE_COLORS[child.boardColumn.category] ?? ""}`}>
                    {child.boardColumn.name}
                  </Badge>
                )}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import {
  Check,
  X,
  Trash2,
  MoreHorizontal,
  MessageSquare,
  History,
  Pencil,
  ChevronRight,
  Maximize2,
} from "lucide-react";
import { ROUTES } from "@/lib/constants";
import { TYPE_CONFIG } from "@/lib/constants/issue-config";
import { useIssue, useUpdateIssue, useDeleteIssue, useProject, useComments } from "../hooks";
import { useWorkspace } from "@/features/workspaces/hooks";
import { useCurrentUser } from "@/features/auth/hooks";
import { useAppStore } from "@/lib/stores/use-app-store";
import { IssueDetailSidebar } from "./issue-detail-sidebar";
import { IssueComments } from "./issue-comments";
import { SubtaskList } from "./subtask-list";
import { AttachmentSection } from "./attachment-section";
import { ActivityFeed } from "./activity-feed";
import { RichEditor, RichContent } from "@/components/shared/rich-editor";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

type Props = {
  issueKey: string;
  /** When in modal mode, show expand button + close button */
  modal?: boolean;
  onClose?: () => void;
};

export function IssueDetailContent({ issueKey, modal, onClose }: Props) {
  const router = useRouter();
  const { t } = useAppStore();
  const { user } = useCurrentUser();
  const { data: issue, isLoading } = useIssue(issueKey);
  const { data: project } = useProject(issue?.projectId ?? "");
  const { data: workspace } = useWorkspace(project?.workspaceId ?? "");
  const { data: comments } = useComments(issue?.id ?? "");
  const { mutate: updateIssue } = useUpdateIssue();
  const { mutate: deleteIssue } = useDeleteIssue(issue?.projectId ?? "");

  const [editingSummary, setEditingSummary] = useState(false);
  const [summaryDraft, setSummaryDraft] = useState("");
  const [editingDesc, setEditingDesc] = useState(false);
  const [descDraft, setDescDraft] = useState("");
  const [sidebarWidth, setSidebarWidth] = useState(modal ? 280 : 320);

  function saveSummary() {
    if (issue && summaryDraft.trim() && summaryDraft.trim() !== issue.summary) {
      updateIssue({ id: issue.id, summary: summaryDraft.trim() });
    }
    setEditingSummary(false);
  }

  function saveDesc() {
    const newDesc = descDraft.trim() || null;
    if (issue && newDesc !== (issue.description ?? null)) {
      updateIssue({ id: issue.id, description: newDesc });
    }
    setEditingDesc(false);
  }

  function handleUpdate(field: string, value: string | null) {
    if (!issue) return;
    const current = (issue as Record<string, unknown>)[field];
    const currentStr = current != null ? String(current) : null;
    if (value === currentStr) return; // No change — skip API call
    let parsed: unknown = value;
    if (field === "storyPoints") parsed = value ? parseInt(value) : null;
    updateIssue({ id: issue.id, [field]: parsed });
  }

  function handleExpand() {
    onClose?.();
    router.push(ROUTES.ISSUE(issueKey));
  }

  if (isLoading) {
    return (
      <div className="p-6">
        <Skeleton className="mb-4 h-6 w-32" />
        <Skeleton className="mb-2 h-8 w-96" />
        <Skeleton className="h-40 w-full" />
      </div>
    );
  }

  if (!issue) {
    return (
      <div className="flex h-64 items-center justify-center">
        <p className="text-muted-foreground">{t("issue.notFound")}</p>
      </div>
    );
  }

  const typeConf = TYPE_CONFIG[issue.type] ?? TYPE_CONFIG.TASK;
  const TypeIcon = typeConf.icon;

  return (
    <div className="flex h-full flex-col">
      {/* Top bar — full width */}
      <div className="flex shrink-0 items-center justify-between border-b px-5 py-2.5">
        {/* Breadcrumb */}
        <div className="flex items-center gap-1 text-[12px]">
          {!modal && workspace && (
            <>
              <Link href={ROUTES.WORKSPACE(workspace.id)} className="text-muted-foreground hover:text-foreground hover:underline">
                {workspace.name}
              </Link>
              <ChevronRight className="h-3 w-3 text-muted-foreground/40" />
            </>
          )}
          {!modal && project && workspace && (
            <>
              <Link href={ROUTES.BOARD(workspace.id, project.id)} className="text-muted-foreground hover:text-foreground hover:underline">
                {project.key}
              </Link>
              <ChevronRight className="h-3 w-3 text-muted-foreground/40" />
            </>
          )}
          {issue.parent && (
            <>
              <Link href={ROUTES.ISSUE(issue.parent.key)} className="text-muted-foreground hover:text-foreground hover:underline">
                {issue.parent.key}
              </Link>
              <ChevronRight className="h-3 w-3 text-muted-foreground/40" />
            </>
          )}
          <div className="flex items-center gap-1.5">
            <div className={`flex h-4.5 w-4.5 items-center justify-center rounded-sm ${typeConf.bg}`}>
              <TypeIcon className="h-2.5 w-2.5 text-white" />
            </div>
            <span className="font-medium text-foreground">{issue.key}</span>
          </div>
        </div>

        <div className="flex items-center gap-1">
          {modal && (
            <>
              <Button variant="ghost" size="icon-xs" onClick={handleExpand} title="Open full page">
                <Maximize2 className="h-4 w-4" />
              </Button>
              <Button variant="ghost" size="icon-xs" onClick={onClose}>
                <X className="h-4 w-4" />
              </Button>
            </>
          )}
          <DropdownMenu>
            <Button render={<DropdownMenuTrigger />} variant="ghost" size="xs">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
            <DropdownMenuContent align="end">
              <DropdownMenuItem
                onClick={() => { deleteIssue(issue.id); modal ? onClose?.() : router.back(); }}
                className="text-destructive"
              >
                <Trash2 className="mr-2 h-3.5 w-3.5" />
                {t("issue.deleteIssue")}
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>

      {/* Body — main + resize + sidebar */}
      <div className="flex min-h-0 flex-1 overflow-hidden">
      {/* Main content */}
      <div className="flex-1 overflow-auto">
        <div className="px-6 py-5">
          {/* Summary — inline edit */}
          {editingSummary ? (
            <div className="mb-5 flex items-center gap-2">
              <Input
                value={summaryDraft}
                onChange={(e) => setSummaryDraft(e.target.value)}
                onKeyDown={(e) => { if (e.key === "Enter") saveSummary(); if (e.key === "Escape") setEditingSummary(false); }}
                className="text-lg font-semibold"
                autoFocus
              />
              <Button size="xs" onClick={saveSummary}><Check className="h-3.5 w-3.5" /></Button>
              <Button size="xs" variant="ghost" onClick={() => setEditingSummary(false)}><X className="h-3.5 w-3.5" /></Button>
            </div>
          ) : (
            <h1
              className="group/edit mb-5 cursor-pointer rounded-md px-2 py-1 text-lg font-semibold leading-tight transition-colors duration-150 hover:bg-muted/60 dark:hover:bg-muted/30"
              onClick={() => { setEditingSummary(true); setSummaryDraft(issue.summary); }}
            >
              {issue.summary}
              <span className="ml-2 inline-block opacity-0 transition-opacity group-hover/edit:opacity-60">
                <Pencil className="inline h-3.5 w-3.5" />
              </span>
            </h1>
          )}

          {/* Description — inline edit */}
          <div className="mb-6">
            <h3 className="mb-2 text-[12px] font-semibold uppercase tracking-wide text-muted-foreground">
              {t("common.description")}
            </h3>
            {editingDesc ? (
              <div className="space-y-2">
                <RichEditor content={descDraft} onChange={setDescDraft} placeholder={t("issue.descPlaceholder")} autoFocus />
                <div className="flex gap-2">
                  <Button size="xs" onClick={saveDesc}>{t("common.save")}</Button>
                  <Button size="xs" variant="ghost" onClick={() => setEditingDesc(false)}>{t("common.cancel")}</Button>
                </div>
              </div>
            ) : (
              <div
                className="group/desc cursor-pointer rounded-md border border-transparent p-3 transition-all duration-150 hover:border-muted-foreground/20 hover:bg-muted/40 dark:hover:bg-muted/20"
                onClick={() => { setEditingDesc(true); setDescDraft(issue.description ?? ""); }}
              >
                {issue.description ? (
                  <RichContent html={issue.description} />
                ) : (
                  <p className="text-sm italic text-muted-foreground/50">{t("issue.clickToAddDesc")}</p>
                )}
                <span className="mt-1 block text-[10px] text-muted-foreground/40 opacity-0 transition-opacity group-hover/desc:opacity-100">
                  <Pencil className="mr-1 inline h-3 w-3" />{t("common.edit")}
                </span>
              </div>
            )}
          </div>

          {/* Attachments */}
          <AttachmentSection issueId={issue.id} currentUserId={user?.id ?? ""} />

          {/* Subtasks */}
          <SubtaskList issue={issue} />

          <Separator className="mb-5" />

          {/* Tabs: Comments / Activity */}
          <Tabs defaultValue="comments">
            <TabsList variant="line" className="mb-4">
              <TabsTrigger value="comments">
                <MessageSquare className="mr-1.5 h-3.5 w-3.5" />
                {t("issue.comments")} {comments?.length ? `(${comments.length})` : ""}
              </TabsTrigger>
              <TabsTrigger value="activity">
                <History className="mr-1.5 h-3.5 w-3.5" />
                {t("issue.activity")}
              </TabsTrigger>
            </TabsList>

            <TabsContent value="comments">
              <IssueComments issueId={issue.id} currentUser={{ id: user?.id ?? "", name: user?.name ?? null }} />
            </TabsContent>

            <TabsContent value="activity">
              <ActivityFeed issueId={issue.id} />
            </TabsContent>
          </Tabs>
        </div>
      </div>

      {/* Resize handle */}
      <div
        className="group/resize relative w-1.5 shrink-0 cursor-col-resize"
        onMouseDown={(e) => {
          e.preventDefault();
          const startX = e.clientX;
          const startWidth = sidebarWidth;
          function onMove(ev: MouseEvent) {
            const delta = startX - ev.clientX;
            setSidebarWidth(Math.max(240, Math.min(500, startWidth + delta)));
          }
          function onUp() {
            document.removeEventListener("mousemove", onMove);
            document.removeEventListener("mouseup", onUp);
          }
          document.addEventListener("mousemove", onMove);
          document.addEventListener("mouseup", onUp);
        }}
      >
        <div className="mx-auto h-full w-px bg-border transition-colors group-hover/resize:w-0.5 group-hover/resize:bg-primary/40 group-active/resize:bg-primary/60" />
      </div>

      {/* Sidebar */}
      <div style={{ width: sidebarWidth }} className="shrink-0">
        <IssueDetailSidebar
          issue={issue}
          members={project?.members ?? []}
          currentUserId={user?.id ?? ""}
          onUpdate={handleUpdate}
        />
      </div>
      </div>
    </div>
  );
}

"use client";

